timeSeriesQuery.prometheusQuery:
(
  avg by (machine_id) (
    avg_over_time({
      __name__="edgecontainer.googleapis.com/machine/power_consumption",
      monitored_resource="edgecontainer.googleapis.com/Machine",
      machine_id=~"${machine_id.value}"
    }[${__interval}])
  ) < 125
)
* on (machine_id) group_left(cluster_name)
(
  label_replace(
    max by (cluster_name, machine_name) (
      last_over_time({
        __name__="edgecontainer.googleapis.com/node/current_node_version",
        monitored_resource="edgecontainer.googleapis.com/Node",
        cluster_name=~"${cluster_name.value}"
      }[5m])
    ),
    "machine_id", "$1", "machine_name", ".*/machines/(.*)"
  )
)

(
  sum by (machine_id) (
    rate({
      __name__="edgecontainer.googleapis.com/machine/restart_count",
      monitored_resource="edgecontainer.googleapis.com/Machine",
      machine_id=~"${machine_id.value}"
    }[${__interval}])
  )
)
* on (machine_id) group_left(cluster_name)
(
  label_replace(
    max by (cluster_name, machine_name) (
      last_over_time({
        __name__="edgecontainer.googleapis.com/node/current_node_version",
        monitored_resource="edgecontainer.googleapis.com/Node",
        cluster_name=~"${cluster_name.value}"
      }[5m])
    ),
    "machine_id", "$1", "machine_name", ".*/machines/(.*)"
  )
)

avg by (cluster_name) (
  (
    # Get temperatures for machines in alert state
    sum by (machine_id) (
      min_over_time({
        __name__="edgecontainer.googleapis.com/machine/ambient_temperature",
        monitored_resource="edgecontainer.googleapis.com/Machine",
        machine_id=~"${machine_id.value}"
      }[96h])
    ) > 40
  )
  * on (machine_id) group_left(cluster_name)
  (
    label_replace(
      max by (cluster_name, machine_name) (
        last_over_time({
          __name__="edgecontainer.googleapis.com/node/current_node_version",
          monitored_resource="edgecontainer.googleapis.com/Node",
          cluster_name=~"${cluster_name.value}"
        }[5m])
      ),
      "machine_id", "$1", "machine_name", ".*/machines/(.*)"
    )
  )
)

avg by (cluster_name) (
  (
    # Get temperatures for machines in alert state
    sum by (machine_id) (
      avg_over_time({
        __name__="edgecontainer.googleapis.com/machine/ambient_temperature",
        monitored_resource="edgecontainer.googleapis.com/Machine",
        machine_id=~"${machine_id.value}"
      }[${__interval}])
    ) > 40
    or 
    sum by (machine_id) (
      avg_over_time({
        __name__="edgecontainer.googleapis.com/machine/ambient_temperature",
        monitored_resource="edgecontainer.googleapis.com/Machine",
        machine_id=~"${machine_id.value}"
      }[${__interval}])
    ) < 10
  )
  * on (machine_id) group_left(cluster_name)
  (
    label_replace(
      max by (cluster_name, machine_name) (
        last_over_time({
          __name__="edgecontainer.googleapis.com/node/current_node_version",
          monitored_resource="edgecontainer.googleapis.com/Node",
          cluster_name=~"${cluster_name.value}"
        }[5m])
      ),
      "machine_id", "$1", "machine_name", ".*/machines/(.*)"
    )
  )
)
